import{_ as t,o as a,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"65. Leave To Engage In Voluntary Emergency Management","description":"","frontmatter":{"title":"65. Leave To Engage In Voluntary Emergency Management","eba":"Biomedical Engineers 2025-2028","topics":["leave","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/65-leave-to-engage-in-voluntary-emergency-management.md","filePath":"ebas/biomedical-engineers/leave/65-leave-to-engage-in-voluntary-emergency-management.md"}'),i={name:"ebas/biomedical-engineers/leave/65-leave-to-engage-in-voluntary-emergency-management.md"};function r(s,e,m,l,g,c){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_65-leave-to-engage-in-voluntary-emergency-management" tabindex="-1">65. Leave To Engage In Voluntary Emergency Management <a class="header-anchor" href="#_65-leave-to-engage-in-voluntary-emergency-management" aria-label="Permalink to &quot;65. Leave To Engage In Voluntary Emergency Management&quot;">​</a></h1><p>Activities</p><p><strong>65.1</strong> An Employee who engages in a voluntary emergency management activity with a recognised emergency management body that requires the attendance of the Employee at a time when the Employee would otherwise be required to be at work is entitled to paid/unpaid leave for:</p><p><strong>(a)</strong> time when the Employee engages in the activity;</p><p><strong>(b)</strong> reasonable travelling time associated with the activity; and</p><p><strong>(c)</strong> reasonable rest time immediately following the activity.</p><p><strong>65.2</strong> The Employee must advise the Employer as soon as reasonably practicable, which may be at a time after the absence has started, if the Employee is requested to attend a voluntary emergency management activity and must advise the Employer of the expected or likely duration of the Employee’s attendance. The Employee must provide a certificate of attendance or other evidence that would satisfy a reasonable person of attendance where requested by the Employer.</p><p><strong>65.3</strong> Recognised emergency management bodies include but are not limited to, the Country Fire Authority, Red Cross, State Emergency Service and St John Ambulance.</p><p><strong>65.4</strong> An Employee who is required to attain qualifications or to requalify to perform activities in an emergency management body must be granted leave with pay for the period of time required to fulfil the requirements of the training course pertaining to those qualifications, provided that such training can be undertaken without unduly affecting the operations of the Employer.</p><p><strong>65.5</strong> The leave under this clause 65 will be paid up to two (2) weeks per calendar year, save that approval of paid leave is subject to the operational requirements of the Employer resulting from any emergency.</p><p><strong>65.6</strong> Nothing in this clause 65 limits the ability of an Employee to be absent from employment for engaging in eligible community service activity in accordance with Division 8 of the Act.</p>',11)])])}const d=t(i,[["render",r]]);export{p as __pageData,d as default};
